module traffic_light(
    input rst_n,
    input clk,
    input pass_request,
    output reg [7:0] clock_value,
    output reg red,
    output reg yellow,
    output reg green
);

localparam IDLE = 2'b00;
localparam RED = 2'b01;
localparam YELLOW = 2'b10;
localparam GREEN = 2'b11;

reg [1:0] state;
reg [7:0] counter;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= IDLE;
        counter <= 8'd0;
        clock_value <= 8'd0;
        red <= 1'b0;
        yellow <= 1'b0;
        green <= 1'b0;
    end else begin
        case (state)
            IDLE: begin
                red <= 1'b0;
                yellow <= 1'b0;
                green <= 1'b1;
                counter <= 8'd39;
                state <= RED;
            end
            RED: begin
                red <= 1'b1;
                yellow <= 1'b0;
                green <= 1'b0;
                if (counter == 8'd0) begin
                    state <= YELLOW;
                    counter <= 8'd3;
                end else begin
                    counter <= counter - 1;
                end
            end
            YELLOW: begin
                red <= 1'b1;
                yellow <= 1'b1;
                green <= 1'b0;
                if (counter == 8'd0) begin
                    state <= GREEN;
                    counter <= 8'd3;
                end else begin
                    counter <= counter - 1;
                end
            end
            GREEN: begin
                red <= 1'b0;
                yellow <= 1'b0;
                green <= 1'b1;
                if (counter == 8'd0) begin
                    state <= RED;
                    counter <= 8'd39;
                end else begin
                    counter <= counter - 1;
                end
            end
            default: begin
                state <= IDLE;
            end
    endcase
end

assign clock_value = counter;

end // Auto-repaired
endmodule

module multi_16bit(
    input clk, input rst_n, input start, input [15:0] ain, input [15:0] bin,
    output reg [31:0] yout, output reg done
); 
    integer i;
    reg [15:0] areg, breg;
    reg [31:0] yout_r;
    reg done_r;

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            i <= 0;
        end
        else begin
            if(start && i < 17) begin
                i <= i + 1;
            end
            else begin
                i <= 0;
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            done_r <= 0;
        end
        else begin
            if(i == 16) begin
                done_r <= 1;
            end
            else if(i == 17) begin
                done_r <= 0;
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            areg <= 0;
            breg <= 0;
            yout_r <= 0;
        end
        else begin
            if(start) begin
                if(i == 0) begin
                    areg <= ain;
                    breg <= bin;
                end
                else if(i > 0 && i < 17) begin
                    if(areg[i-1]) begin
                        yout_r <= yout_r + (breg << (i-1));
                    end
                end
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            yout <= 0;
            done <= 0;
        end
        else begin
            yout <= yout_r;
            done <= done_r;
        end
    end
endmodule

module multi_pipe_8bit(
