module div_16bit(
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

always @(A or B) begin

    reg [15:0] a_reg = A;
    reg [7:0] b_reg = B;

    for (int i = 0; i < 16; i++) begin

        a_reg = {a_reg[14:0], 1'b0};

        int diff = a_reg[15:8] - b_reg;
        if (diff >= 0) begin

            result[i] = 1'b1;

            a_reg[15:8] = diff;
        end else begin

            result[i] = 1'b0;

            a_reg[15:8] = a_reg[15:8] + b_reg;
        end
    end

    odd = a_reg;
end

endmodule

