module asyn_fifo(
    input wclk, rclk, wrstn, rrstn, winc, rinc,
    input [7:0] wdata,
    output wfull, rempty,
    output [7:0] rdata
);
    parameter WIDTH = 8;
    parameter DEPTH = 16;

    wire wen, ren;
    wire [3:0] wptr, rptr, wptr_syn, rptr_syn;
    reg [3:0] waddr_bin, raddr_bin;
    reg [3:0] wptr_buff, rptr_buff;
    wire [3:0] waddr, raddr;
    wire [WIDTH-1:0] rdata_tmp;
    assign wen = winc && wrstn;
    assign ren = rinc && rrstn;
    assign waddr = waddr_bin[$clog2(DEPTH)-1:0];
    assign raddr = raddr_bin[$clog2(DEPTH)-1:0];
    assign wptr = {waddr_bin[3], waddr_bin[3]^waddr_bin[2], waddr_bin[2]^waddr_bin[1], waddr_bin[1]^waddr_bin[0]};
    assign rptr = {raddr_bin[3], raddr_bin[3]^raddr_bin[2], raddr_bin[2]^raddr_bin[1], raddr_bin[1]^raddr_bin[0]};
    assign wptr_syn = {waddr_bin[3], waddr_bin[3]^waddr_bin[2], waddr_bin[2]^waddr_bin[1], waddr_bin[1]^waddr_bin[0]};
    assign rptr_syn = {raddr_bin[3], raddr_bin[3]^raddr_bin[2], raddr_bin[2]^raddr_bin[1], raddr_bin[1]^raddr_bin[0]};
    assign wfull = (wptr == {~rptr_buff[3], rptr_buff[2:0]});
    assign rempty = (rptr == wptr);
    always @(posedge wclk or negedge wrstn) begin
        if (!wrstn)
            waddr_bin <= 4'd0;
        else if (winc)
            waddr_bin <= waddr_bin + 1;
    end
    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn)
            raddr_bin <= 4'd0;
        else if (rinc)
            raddr_bin <= raddr_bin + 1;
    end
    always @(posedge wclk or negedge wrstn) begin
        if (!wrstn)
            wptr_buff <= 4'd0;
            wptr_buff <= wptr;
    end
    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn)
            rptr_buff <= 4'd0;
            rptr_buff <= rptr;
    end
    dual_port_RAM #(.WIDTH(WIDTH), .DEPTH(DEPTH)) ram (
        .wclk(wclk),
        .wenc(wen),
        .waddr(waddr),
        .wdata(wdata),
        .rclk(rclk),
        .renc(ren),
        .raddr(raddr),
        .rdata(rdata_tmp)
    );
