module accu(
    input clk, input rst_n, input [7:0] data_in, input valid_in,
    output reg valid_out, output reg [9:0] data_out
);
    reg [3:0] cnt;
    reg [9:0] accu_data;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 4'b0;
            accu_data <= 10'b0;
            valid_out <= 1'b0;
            data_out <= 10'b0;
        end else begin
            if (valid_in) begin
                if (cnt < 4'b100) begin
                    accu_data <= accu_data + data_in;
                    cnt <= cnt + 1;
                end else begin
                    valid_out <= 1'b1;
                    data_out <= accu_data;
                    cnt <= 4'b0;
                    accu_data <= 10'b0;
                end
            end else begin
                valid_out <= 1'b0;
            end
        end
    end

endmodule

module JC_counter(
    input clk, input rst_n,
    output reg [63:0] Q
);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        Q <= 64'b0;
    end else begin
        if (Q[0] == 1'b0) begin
            Q <= {Q[62:0], 1'b1};
        end else begin
            Q <= {1'b0, Q[63:1]};
        end
    end
end

endmodule

module RAM (
    input clk,
    input rst_n,
    input write_en,
    input [2:0] write_addr,
    input [5:0] write_data,
    input read_en,
    input [2:0] read_addr,
    output reg [5:0] read_data
);
    parameter WIDTH = 6;
    parameter DEPTH = 8;

    reg [WIDTH-1:0] RAM [DEPTH-1:0];
    integer i;
    initial begin
        for (i = 0; i < DEPTH; i = i + 1) begin
            RAM[i] = 6'b000000;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (i = 0; i < DEPTH; i = i + 1) begin
                RAM[i] <= 6'b000000;
            end
        end else if (write_en) begin
            RAM[write_addr] <= write_data;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            read_data <= 6'b000000;
        end else if (read_en) begin
            read_data <= RAM[read_addr];
        end else begin
            read_data <= 6'b000000;
        end
    end
endmodule

module right_shifter(
    input clk, input d,
    output reg [7:0] q
); 
initial begin
    q = 8'b0;
end
always @(posedge clk) begin
    q <= (q >> 1);
    q[7] <= d;
end
endmodule

module synchronizer (
    input clk_a,
    input clk_b,
    input arstn,
    input brstn,
    input [3:0] data_in,
    input data_en,
    output reg [3:0] dataout
);

reg [3:0] data_reg;
always @(posedge clk_a or negedge arstn) begin
    if (!arstn) begin
        data_reg <= 4'b0;
    end else begin
        data_reg <= data_in;
    end
end

reg en_data_reg;
always @(posedge clk_a or negedge arstn) begin
    if (!arstn) begin
        en_data_reg <= 1'b0;
    end else begin
        en_data_reg <= data_en;
    end
end

reg en_clap_one, en_clap_two;
always @(posedge clk_b or negedge brstn) begin
    if (!brstn) begin
        en_clap_one <= 1'b0;
        en_clap_two <= 1'b0;
    end else begin
        en_clap_one <= en_data_reg;
        en_clap_two <= en_clap_one;
    end
end

always @(posedge clk_b or negedge brstn) begin
    if (!brstn) begin
        dataout <= 4'b0;
    end else begin
        if (en_clap_two) begin
            dataout <= data_reg;
        end else begin
            dataout <= dataout;
        end
    end
end
endmodule
